class MetadataBuilder:
    """
    Builds gRPC metadata from HTTP headers and user input.
    
    Handles header filtering, transformation, and validation
    before passing them as gRPC metadata.
    """

    # Headers that should be forwarded from HTTP to gRPC
    FORWARDED_HEADER_PREFIXES = [
        "x-custom-",
        "x-request-",
        "x-trace-",
        "x-correlation-",
        "x-user-",
        "x-tenant-",
        "authorization",
        "x-api-key",
    ]

    # Headers that should never be forwarded
    BLOCKED_HEADERS = {
        "host",
        "content-length",
        "transfer-encoding",
        "connection",
        "keep-alive",
        "upgrade",
    }

    # gRPC metadata keys must be lowercase ASCII and may contain hyphens/underscores
    @staticmethod
    def sanitize_key(key: str) -> str:
        """Sanitize a header key for use as gRPC metadata key."""
        sanitized = key.lower().strip()
        sanitized = ''.join(c if c.isalnum() or c in '-_.' else '-' for c in sanitized)
        return sanitized

    @classmethod
    def should_forward_header(cls, header_name: str) -> bool:
        """Determine if an HTTP header should be forwarded as gRPC metadata."""
        header_lower = header_name.lower()

        if header_lower in cls.BLOCKED_HEADERS:
            return False

        for prefix in cls.FORWARDED_HEADER_PREFIXES:
            if header_lower.startswith(prefix):
                return True

        return False

    @classmethod
    def build_metadata_from_http_headers(
        cls, 
        http_headers: Dict[str, str],
        additional_metadata: Optional[Dict[str, str]] = None
    ) -> List[Tuple[str, str]]:
        """
        Build gRPC metadata from HTTP headers.
        
        Args:
            http_headers: Dictionary of HTTP headers
            additional_metadata: Extra metadata to include
            
        Returns:
            List of (key, value) tuples suitable for gRPC metadata
        """
        metadata = []

        # Filter and transform HTTP headers
        for key, value in http_headers.items():
            if cls.should_forward_header(key):
                sanitized_key = cls.sanitize_key(key)
                metadata.append((sanitized_key, str(value)))

        # Add additional metadata
        if additional_metadata:
            for key, value in additional_metadata.items():
                sanitized_key = cls.sanitize_key(key)
                metadata.append((sanitized_key, str(value)))

        # Add gateway-specific metadata
        metadata.append(("x-gateway-timestamp", str(time.time())))
        metadata.append(("x-gateway-version", "1.0.0"))

        return metadata

    @classmethod
    def build_metadata_from_user_input(
        cls,
        user_id: Optional[str] = None,
        tenant_id: Optional[str] = None,
        correlation_id: Optional[str] = None,
        custom_fields: Optional[Dict[str, str]] = None
    ) -> List[Tuple[str, str]]:
        """
        Build gRPC metadata from structured user input.
        
        Args:
            user_id: User identifier
            tenant_id: Tenant identifier
            correlation_id: Request correlation ID
            custom_fields: Additional custom metadata fields
            
        Returns:
            List of (key, value) tuples suitable for gRPC metadata
        """
        metadata = []

        if user_id:
            metadata.append(("x-user-id", user_id))
        if tenant_id:
            metadata.append(("x-tenant-id", tenant_id))
        if correlation_id:
            metadata.append(("x-correlation-id", correlation_id))

        if custom_fields:
            for key, value in custom_fields.items():
                sanitized_key = cls.sanitize_key(key)
                metadata.append((sanitized_key, str(value)))

        return metadata

    @classmethod
    def merge_metadata(
        cls,
        *metadata_lists: List[Tuple[str, str]]
    ) -> List[Tuple[str, str]]:
        """Merge multiple metadata lists, with later lists taking precedence."""
        seen_keys = {}
        for md_list in metadata_lists:
            for key, value in md_list:
                seen_keys[key] = value

        return list(seen_keys.items())


