class BackendServiceClient:
    """
    gRPC client that forwards requests to backend services with metadata.
    """

    def __init__(self, target: str, use_tls: bool = False, timeout: float = 30.0):
        """
        Initialize the backend service client.
        
        Args:
            target: Backend service address (host:port)
            use_tls: Whether to use TLS for the connection
            timeout: Default timeout for RPCs in seconds
        """
        self.target = target
        self.timeout = timeout

        if use_tls:
            credentials = grpc.ssl_channel_credentials()
            self.channel = grpc.secure_channel(target, credentials)
        else:
            self.channel = grpc.insecure_channel(target)

        # Define method descriptors
        self._forward_method = '/gateway.BackendService/ForwardRequest'
        self._health_method = '/gateway.BackendService/HealthCheck'

    def close(self):
        """Close the gRPC channel."""
        if self.channel:
            self.channel.close()

    def forward_request(
        self,
        request: GatewayRequest,
        metadata: List[Tuple[str, str]],
        timeout: Optional[float] = None
    ) -> Tuple[GatewayResponse, List[Tuple[str, str]], List[Tuple[str, str]]]:
        """
        Forward a request to the backend service with metadata.
        
        Args:
            request: The gateway request to forward
            metadata: gRPC metadata to attach to the call
            timeout: Optional timeout override
            
        Returns:
            Tuple of (response, initial_metadata, trailing_metadata)
        """
        call_timeout = timeout or self.timeout

        # Create the unary-unary callable
        method = self.channel.unary_unary(
            self._forward_method,
            request_serializer=_request_serializer,
            response_deserializer=_response_deserializer,
        )

        # Make the call with metadata
        call = method.future(
            request,
            metadata=metadata,
            timeout=call_timeout,
        )

        # Get the response and metadata
        response = call.result()
        initial_metadata = list(call.initial_metadata())
        trailing_metadata = list(call.trailing_metadata())

        return response, initial_metadata, trailing_metadata

    def health_check(
        self,
        service_name: str,
        metadata: Optional[List[Tuple[str, str]]] = None
    ) -> HealthCheckResponse:
        """
        Check the health of a backend service.
        
        Args:
            service_name: Name of the service to check
            metadata: Optional metadata to attach
            
        Returns:
            HealthCheckResponse
        """
        method = self.channel.unary_unary(
            self._health_method,
            request_serializer=_health_request_serializer,
            response_deserializer=_health_response_deserializer,
        )

        request = HealthCheckRequest(service_name=service_name)
        response = method(
            request,
            metadata=metadata or [],
            timeout=self.timeout,
        )

        return response


