class GatewayServiceServicer:
    """
    gRPC servicer for the API Gateway.
    
    Receives requests from external clients, builds metadata from
    the incoming request headers, and forwards to backend services.
    """

    def __init__(self, backend_registry: Dict[str, str]):
        """
        Initialize the gateway servicer.
        
        Args:
            backend_registry: Mapping of service names to their addresses
        """
        self.backend_registry = backend_registry
        self.backend_clients: Dict[str, BackendServiceClient] = {}
        self.metadata_builder = MetadataBuilder()

        # Initialize backend clients
        for service_name, address in backend_registry.items():
            self.backend_clients[service_name] = BackendServiceClient(address)

    def ForwardRequest(self, request: GatewayRequest, context) -> GatewayResponse:
        """
        Handle incoming gateway request and forward to backend.
        
        This method:
        1. Extracts metadata from the incoming gRPC context
        2. Builds additional metadata from the request
        3. Forwards the request to the appropriate backend service
        4. Sets trailing metadata on the response context
        """
        try:
            # Step 1: Extract incoming metadata from the client
            incoming_metadata = dict(context.invocation_metadata())
            print(f"[Gateway] Received request for service: {request.service_name}")
            print(f"[Gateway] Incoming metadata: {incoming_metadata}")

            # Step 2: Build metadata from HTTP headers in the request
            http_header_metadata = self.metadata_builder.build_metadata_from_http_headers(
                http_headers=request.headers,
                additional_metadata={
                    "x-gateway-source": "api-gateway",
                    "x-original-method": request.method,
                }
            )

            # Step 3: Build metadata from user input / context
            user_metadata = self.metadata_builder.build_metadata_from_user_input(
                user_id=incoming_metadata.get("x-user-id"),
                tenant_id=incoming_metadata.get("x-tenant-id"),
                correlation_id=incoming_metadata.get("x-correlation-id"),
                custom_fields={
                    "x-forwarded-for": incoming_metadata.get("x-forwarded-for", "unknown"),
                }
            )

            # Step 4: Merge all metadata sources
            combined_metadata = self.metadata_builder.merge_metadata(
                http_header_metadata,
                user_metadata,
                list(incoming_metadata.items()),
            )

            print(f"[Gateway] Combined metadata for backend: {combined_metadata}")

            # Step 5: Find the backend client
            backend_client = self.backend_clients.get(request.service_name)
            if not backend_client:
                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details(f"Service '{request.service_name}' not found in registry")
                # Set trailing metadata with error info
                context.set_trailing_metadata([
                    ("x-gateway-error", "service-not-found"),
                    ("x-gateway-timestamp", str(time.time())),
                ])
                return GatewayResponse(
                    status_code=404,
                    body=json.dumps({"error": f"Service '{request.service_name}' not found"}),
                )

            # Step 6: Forward the request to the backend
            try:
                response, initial_md, trailing_md = backend_client.forward_request(
                    request=request,
                    metadata=combined_metadata,
                )

                # Step 7: Set trailing metadata from backend response + gateway info
                response_trailing_metadata = [
                    ("x-gateway-status", "success"),
                    ("x-gateway-timestamp", str(time.time())),
                    ("x-backend-service", request.service_name),
                ]

                # Forward backend trailing metadata
                for key, value in trailing_md:
                    response_trailing_metadata.append((f"x-backend-{key}", value))

                context.set_trailing_metadata(response_trailing_metadata)

                return response

            except grpc.RpcError as rpc_error:
                print(f"[Gateway] Backend RPC error: {rpc_error}")
                
                # Set trailing metadata with error information
                context.set_trailing_metadata([
                    ("x-gateway-error", "backend-rpc-error"),
                    ("x-gateway-error-code", str(rpc_error.code())),
                    ("x-gateway-error-details", str(rpc_error.details())),
                    ("x-gateway-timestamp", str(time.time())),
                ])

                context.set_code(rpc_error.code())
                context.set_details(f"Backend error: {rpc_error.details()}")

                return GatewayResponse(
                    status_code=502,
                    body=json.dumps({
                        "error": "Backend service error",
                        "details": str(rpc_error.details()),
                    }),
                )

        except Exception as e:
            print(f"[Gateway] Unexpected error: {e}")
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details(f"Internal gateway error: {str(e)}")
            context.set_trailing_metadata([
                ("x-gateway-error", "internal-error"),
                ("x-gateway-timestamp", str(time.time())),
            ])
            return GatewayResponse(
                status_code=500,
                body=json.dumps({"error": "Internal gateway error"}),
            )

    def HealthCheck(self, request: HealthCheckRequest, context) -> HealthCheckResponse:
        """Health check endpoint for the gateway itself."""
        context.set_trailing_metadata([
            ("x-gateway-health", "ok"),
            ("x-gateway-timestamp", str(time.time())),
        ])
        return HealthCheckResponse(
            healthy=True,
            message="API Gateway is healthy"
        )

    def shutdown(self):
        """Shut down all backend clients."""
        for client in self.backend_clients.values():
            client.close()


