class GatewayClient:
    """
    Client for calling the API Gateway service.
    
    This simulates an HTTP-to-gRPC translation layer that
    external services would use to communicate with the gateway.
    """

    def __init__(self, gateway_address: str):
        self.channel = grpc.insecure_channel(gateway_address)

    def send_request(
        self,
        service_name: str,
        method: str,
        payload: str,
        http_headers: Optional[Dict[str, str]] = None,
        user_id: Optional[str] = None,
        tenant_id: Optional[str] = None,
        correlation_id: Optional[str] = None,
    ) -> Tuple[GatewayResponse, List[Tuple[str, str]]]:
        """
        Send a request through the gateway.
        
        Args:
            service_name: Target backend service name
            method: Method to invoke
            payload: Request payload
            http_headers: HTTP headers to forward
            user_id: User identifier
            tenant_id: Tenant identifier
            correlation_id: Correlation ID for tracing
            
        Returns:
            Tuple of (response, trailing_metadata)
        """
        # Build the request
        request = GatewayRequest(
            service_name=service_name,
            method=method,
            payload=payload,
            headers=http_headers or {},
        )

        # Build metadata from user context
        metadata = MetadataBuilder.build_metadata_from_user_input(
            user_id=user_id,
            tenant_id=tenant_id,
            correlation_id=correlation_id,
        )

        # Add any additional HTTP headers as metadata
        if http_headers:
            header_metadata = MetadataBuilder.build_metadata_from_http_headers(http_headers)
            metadata = MetadataBuilder.merge_metadata(metadata, header_metadata)

        # Make the call
        method_callable = self.channel.unary_unary(
            '/gateway.GatewayService/ForwardRequest',
            request_serializer=_request_serializer,
            response_deserializer=_response_deserializer,
        )

        call = method_callable.future(request, metadata=metadata, timeout=30.0)
        response = call.result()
        trailing_metadata = list(call.trailing_metadata())

        return response, trailing_metadata

    def close(self):
        self.channel.close()


